#include <stdio.h>
#include <math.h>

static long long isqrt_ll(long long n) {
    long long r = (long long)sqrt((double)n);
    while ((r+1)*(r+1) <= n) ++r;
    while (r*r > n) --r;
    return r;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long m = isqrt_ll(N);
        long long ans;
        if (N & 1LL) ans = (m + 1) / 2; // odd N → odd k
        else ans = m / 2;               // even N → even k
        printf("%lld\n", ans);
    }
    return 0;
}

