const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
function isqrtBigInt(n) {
  let low = 0n, high = n;
  while (low <= high) {
    const mid = (low + high) >> 1n;
    const sq = mid * mid;
    if (sq === n) return mid;
    if (sq < n) low = mid + 1n; else high = mid - 1n;
  }
  return high; // floor sqrt
}
for (let t = 0; t < T; ++t) {
  const N = BigInt(input[idx++]);
  const m = isqrtBigInt(N);
  const ans = (N & 1n) ? (m + 1n) / 2n : m / 2n;
  results.push(ans.toString());
}
console.log(results.join('\n'));

